159: template <class AbstractorT,
160:           bool AllowAnonAccessT = false>
161: class AWSAuthStrategy : public rgw::auth::Strategy,
162:                         public rgw::auth::LocalApplier::Factory {
163:   typedef rgw::auth::IdentityApplier::aplptr_t aplptr_t;
164: 
165:   static_assert(std::is_base_of<rgw::auth::s3::AWSEngine::VersionAbstractor,
166:                                 AbstractorT>::value,
167:                 "AbstractorT must be a subclass of rgw::auth::s3::VersionAbstractor");
168: 
169:   rgw::sal::Driver* driver;
170:   AbstractorT ver_abstractor;
171: 
172:   S3AnonymousEngine anonymous_engine;
173:   ExternalAuthStrategy external_engines;
174:   STSAuthStrategy sts_engine;
175:   LocalEngine local_engine;
176: 
177:   aplptr_t create_apl_local(CephContext* const cct,
178:                             const req_state* const s,
179:                             const RGWUserInfo& user_info,
180:                             std::optional<RGWAccountInfo> account,
181:                             std::vector<IAM::Policy> policies,
182:                             const std::string& subuser,
183:                             const std::optional<uint32_t>& perm_mask,
184:                             const std::string& access_key_id) const override {
185:     auto apl = rgw::auth::add_sysreq(cct, driver, s,
186:       LocalApplier(cct, user_info, std::move(account), std::move(policies),
187:                    subuser, perm_mask, access_key_id));
188:     /* TODO(rzarzynski): replace with static_ptr. */
189:     return aplptr_t(new decltype(apl)(std::move(apl)));
190:   }
191: 
192: public:
193:   using engine_map_t = std::map <std::string, std::reference_wrapper<const Engine>>;
194:   void add_engines(const std::vector <std::string>& auth_order,
195: 		   engine_map_t eng_map)
196:   {
197:     auto ctrl_flag = Control::SUFFICIENT;
198:     for (const auto &eng : auth_order) {
199:       // fallback to the last engine, in case of multiple engines, since ctrl
200:       // flag is sufficient for others, error from earlier engine is returned
201:       if (&eng == &auth_order.back() && eng_map.size() > 1) {
202:         ctrl_flag = Control::FALLBACK;
203:       }
204:       if (const auto kv = eng_map.find(eng);
205:           kv != eng_map.end()) {
206:         add_engine(ctrl_flag, kv->second);
207:       }
208:     }
209:   }
210: 
211:   auto parse_auth_order(CephContext* const cct)
212:   {
213:     std::vector <std::string> result;
214: 
215:     const std::set <std::string_view> allowed_auth = { "sts", "external", "local" };
216:     std::vector <std::string> default_order = { "sts", "external", "local" };
217:     // supplied strings may contain a space, so let's bypass that
218:     boost::split(result, cct->_conf->rgw_s3_auth_order,
219: 		 boost::is_any_of(", "), boost::token_compress_on);
220: 
221:     if (std::any_of(result.begin(), result.end(),
222: 		    [allowed_auth](std::string_view s)
223: 		    { return allowed_auth.find(s) == allowed_auth.end();})){
224:       return default_order;
225:     }
226:     return result;
227:   }
228: 
229:   AWSAuthStrategy(CephContext* const cct,
230:                   const rgw::auth::ImplicitTenants& implicit_tenant_context,
231:                   rgw::sal::Driver* driver)
232:     : driver(driver),
233:       ver_abstractor(cct),
234:       anonymous_engine(cct,
235:                        static_cast<rgw::auth::LocalApplier::Factory*>(this)),
236:       external_engines(cct, driver, implicit_tenant_context, &ver_abstractor),
237:       sts_engine(cct, driver, implicit_tenant_context, &ver_abstractor),
238:       local_engine(cct, driver, ver_abstractor,
239:                    static_cast<rgw::auth::LocalApplier::Factory*>(this)) {
240:     /* The anonymous auth. */
241:     if (AllowAnonAccessT) {
242:       add_engine(Control::SUFFICIENT, anonymous_engine);
243:     }
244: 
245:     auto auth_order = parse_auth_order(cct);
246:     engine_map_t engine_map;
247: 
248:     /* STS Auth*/
249:     if (! sts_engine.is_empty()) {
250:       engine_map.insert(std::make_pair("sts", std::cref(sts_engine)));
251:     }
252: 
253:     /* The external auth. */
254:     if (! external_engines.is_empty()) {
255:       engine_map.insert(std::make_pair("external", std::cref(external_engines)));
256:     }
257:     /* The local auth. */
258:     if (cct->_conf->rgw_s3_auth_use_rados) {
259:       engine_map.insert(std::make_pair("local", std::cref(local_engine)));
260:     }
261: 
262:     add_engines(auth_order, engine_map);
263:   }
264: 
265:   const char* get_name() const noexcept override {
266:     return "rgw::auth::s3::AWSAuthStrategy";
267:   }
268: }; /* AWSAuthstrategy */
