271:                         public rgw::io::DecoratedRestfulClient<rgw::io::RestfulClient*>,
272:                         public std::enable_shared_from_this<AWSv4ComplMulti> {
273: 
274:   using io_base_t = rgw::io::DecoratedRestfulClient<rgw::io::RestfulClient*>;
275:   using signing_key_t = sha256_digest_t;
276: 
277:   using trailer_map_t = boost::container::flat_map<std::string_view, std::string_view>;
278: 
279:   const req_state* const s;
280: 
281:   const std::string_view date;
282:   const std::string_view credential_scope;
283:   const uint32_t flags;
284:   const signing_key_t signing_key;
