286:   class ChunkMeta {
287:     size_t data_offset_in_stream = 0;
288:     size_t data_length = 0;
289:     std::string signature;
290:     uint32_t flags{FLAG_NONE};
291:     uint32_t cnt;
292: 
293:     ChunkMeta(const size_t data_starts_in_stream,
294:               const size_t data_length,
295:               const std::string_view signature,
296: 	      uint32_t _flags,
297: 	      uint32_t _cnt)
298:       : data_offset_in_stream(data_starts_in_stream),
299:         data_length(data_length),
300:         signature(std::string(signature)),
301: 	flags(_flags),
302: 	cnt(_cnt)
303:     {}
304: 
305:     explicit ChunkMeta(const std::string_view& signature, uint32_t _flags,
306: 		       uint32_t _cnt)
307:       : signature(std::string(signature)), flags(_flags), cnt(_cnt)
308:     {}
309: 
310:   public:
311:     static constexpr size_t SIG_SIZE = 64;
312: 
313:     /* Let's suppose the data length fields can't exceed uint64_t. */
314:     static constexpr size_t META_MAX_SIZE = \
315:       sarrlen("\r\nffffffffffffffff;chunk-signature=") + SIG_SIZE + sarrlen("\r\n");
316: 
317:     /* The metadata size of for the last, empty chunk. */
318:     static constexpr size_t META_MIN_SIZE = \
319:       sarrlen("0;chunk-signature=") + SIG_SIZE + sarrlen("\r\n");
320: 
321:     /* Detect whether a given stream_pos fits in boundaries of a chunk. */
322:     bool is_new_chunk_in_stream(size_t stream_pos) const;
323: 
324:     /* Get the remaining data size. */
325:     size_t get_data_size(size_t stream_pos) const;
326: 
327:     const std::string& get_signature() const {
328:       return signature;
329:     }
330: 
331:     size_t get_offset() { return data_offset_in_stream; }
332: 
333:     /* Factory: create an object representing metadata of first, initial chunk
334:      * in a stream. */
335:     static ChunkMeta create_first(const std::string_view& seed_signature,
336: 				  uint32_t flags,
337: 				  uint32_t cnt) {
338:       return ChunkMeta(seed_signature, flags, cnt);
339:     }
340: 
341:     /* Factory: parse a block of META_MAX_SIZE bytes and creates an object
342:      * representing non-first chunk in a stream. As the process is sequential
343:      * and depends on the previous chunk, caller must pass it. */
344:     static std::pair<ChunkMeta, size_t> create_next(CephContext* cct,
345:                                                     ChunkMeta&& prev,
346:                                                     const char* metabuf,
347:                                                     size_t metabuf_len,
348: 						    uint32_t flags);
349:   } chunk_meta;
350: 
351:   uint16_t lf_bytes;
352:   size_t stream_pos;
353:   boost::container::static_vector<char, ChunkMeta::META_MAX_SIZE> parsing_buf;
354:   boost::optional<std::string_view> x_amz_trailer;
355:   ceph::crypto::SHA256* sha256_hash;
356:   std::string prev_chunk_signature;
357: 
358:   bool is_signature_mismatched();
359:   std::string calc_chunk_signature(const std::string& payload_hash) const;
360: 
361:   struct ReceiveChunkResult {
362:     size_t received;
363:     size_t data_offset_in_stream;
364: 
365:     ReceiveChunkResult(size_t x, size_t y)
366:       : received(x), data_offset_in_stream(y)
367:     {}
368:   }; /* ReceiveChunkResult */
369: 
370:   inline CephContext* cct() const {
371:     return s->cct;
372:   }
373: 
374:   inline bool expect_trailer_signature() const {
375:     return flags & AWSv4ComplMulti::FLAG_TRAILER_SIGNATURE;
376:   }
377: 
378:   inline void put_prop(const std::string_view k, const std::string_view v) {
379:     /* assume the caller will mangle the key name, if required */
380:     auto& map = const_cast<env_map_t&>(s->info.env->get_map());
381:     map.insert(env_map_t::value_type(k, v));
382:   }
383: 
384:   inline void extract_trailing_headers(std::string_view x_amz_trailer,
385: 				       std::string_view& mut_sv_trailer,
386: 				       trailer_map_t& trailer_map);
387: 
388:   std::string calc_v4_trailer_signature(const trailer_map_t& trailer_map,
389: 					const std::string_view last_chunk_sig);
390: 
391:   ReceiveChunkResult recv_chunk(char* buf, size_t max, uint32_t rc_cnt, bool& eof);
392: 
393:   public:
394: 
395:   static constexpr uint32_t FLAG_NONE =              0x00;
396:   static constexpr uint32_t FLAG_TRAILING_CHECKSUM = 0x01;
397:   static constexpr uint32_t FLAG_UNSIGNED_PAYLOAD =  0x02;
398:   static constexpr uint32_t FLAG_UNSIGNED_CHUNKED =  0x04;
399:   static constexpr uint32_t FLAG_TRAILER_SIGNATURE = 0x08;
400: 
401:   /* We need the constructor to be public because of the std::make_shared that
402:    * is employed by the create() method. */
403:   AWSv4ComplMulti(const req_state* const s,
404:                   std::string_view date,
405:                   std::string_view credential_scope,
406:                   std::string_view seed_signature,
407: 		  uint32_t _flags,
408:                   const signing_key_t& signing_key)
409:     : io_base_t(nullptr),
410:       s(s),
411:       date(std::move(date)),
412:       credential_scope(std::move(credential_scope)),
413:       flags(_flags),
414:       signing_key(signing_key),
415: 
416:       /* The evolving state. */
417:       chunk_meta(ChunkMeta::create_first(
418: 		   seed_signature, flags, 0 /* first call in cycle */)),
419:       lf_bytes(0),
420:       stream_pos(0),
421:       sha256_hash(calc_hash_sha256_open_stream()),
422:       prev_chunk_signature(std::move(seed_signature))
423:   {
424:     auto cksum = s->info.env->get("HTTP_X_AMZ_TRAILER");
425:     if (!! cksum) {
426:       x_amz_trailer = std::string_view(cksum, std::strlen(cksum));
427:     }
428:   } /* AWSv4ComplMulti */
429: 
430:   ~AWSv4ComplMulti() {
431:     if (sha256_hash) {
432:       calc_hash_sha256_close_stream(&sha256_hash);
433:     }
434:   }
435: 
436:   /* rgw::io::DecoratedRestfulClient. */
437:   size_t recv_body(char* buf, size_t max) override;
438: 
439:   /* rgw::auth::Completer. */
440:   void modify_request_state(const DoutPrefixProvider* dpp, req_state* s_rw) override;
441:   bool complete() override;
442: 
443:   /* Factories. */
444:   static cmplptr_t create(const req_state* s,
445:                           std::string_view date,
446:                           std::string_view credential_scope,
447:                           std::string_view seed_signature,
448: 			  uint32_t flags,
449:                           const boost::optional<std::string>& secret_key);
450: 
451: };
