554: static inline bool char_needs_aws4_escaping(const char c, bool encode_slash)
555: {
556:   if ((c >= 'a' && c <= 'z') ||
557:       (c >= 'A' && c <= 'Z') ||
558:       (c >= '0' && c <= '9')) {
559:     return false;
560:   }
561: 
562:   switch (c) {
563:     case '-':
564:     case '_':
565:     case '.':
566:     case '~':
567:       return false;
568:   }
569: 
570:   if (c == '/' && !encode_slash)
571:     return false;
572: 
573:   return true;
574: }
575: 
576: static inline std::string aws4_uri_encode(const std::string& src, bool encode_slash)
577: {
578:   std::string result;
579: 
580:   for (const std::string::value_type c : src) {
581:     if (char_needs_aws4_escaping(c, encode_slash)) {
582:       rgw_uri_escape_char(c, result);
583:     } else {
584:       result.push_back(c);
585:     }
586:   }
587: 
588:   return result;
589: }
590: 
591: static inline std::string aws4_uri_recode(const std::string_view& src, bool encode_slash)
592: {
593:   std::string decoded = url_decode(src);
594:   return aws4_uri_encode(decoded, encode_slash);
595: }
596: 
597: static inline std::string get_v4_canonical_uri(const req_info& info) {
598:   /* The code should normalize according to RFC 3986 but S3 does NOT do path
599:    * normalization that SigV4 typically does. This code follows the same
600:    * approach that boto library. See auth.py:canonical_uri(...). */
601: 
602:   std::string canonical_uri = aws4_uri_recode(info.request_uri_aws4, false);
603: 
604:   if (canonical_uri.empty()) {
605:     canonical_uri = "/";
606:   } else {
607:     boost::replace_all(canonical_uri, "+", "%20");
608:   }
609: 
610:   return canonical_uri;
611: }
612: 
613: static inline std::string gen_v4_canonical_uri(const req_info& info) {
614:   /* The code should normalize according to RFC 3986 but S3 does NOT do path
615:    * normalization that SigV4 typically does. This code follows the same
616:    * approach that boto library. See auth.py:canonical_uri(...). */
617: 
618:   std::string canonical_uri = aws4_uri_recode(info.request_uri, false);
619: 
620:   if (canonical_uri.empty()) {
621:     canonical_uri = "/";
622:   } else {
623:     boost::replace_all(canonical_uri, "+", "%20");
624:   }
625: 
626:   return canonical_uri;
627: }
