629: static inline const string calc_v4_payload_hash(const string& payload)
630: {
631:   ceph::crypto::SHA256* sha256_hash = calc_hash_sha256_open_stream();
632:   calc_hash_sha256_update_stream(sha256_hash, payload.c_str(), payload.length());
633:   const auto payload_hash = calc_hash_sha256_close_stream(&sha256_hash);
634:   return payload_hash;
635: }
636: 
637: static inline const char* get_v4_exp_payload_hash(const req_info& info)
638: {
639:   /* In AWSv4 the hash of real, transferred payload IS NOT necessary to form
640:    * a Canonical Request, and thus verify a Signature. x-amz-content-sha256
641:    * header lets get the information very early -- before seeing first byte
642:    * of HTTP body. As a consequence, we can decouple Signature verification
643:    * from payload's fingerprint check. */
644:   const char *expected_request_payload_hash = \
645:     info.env->get("HTTP_X_AMZ_CONTENT_SHA256");
646: 
647:   if (!expected_request_payload_hash) {
648:     /* An HTTP client MUST send x-amz-content-sha256. The single exception
649:      * is the case of using the Query Parameters where "UNSIGNED-PAYLOAD"
650:      * literals are used for crafting Canonical Request:
651:      *
652:      *  You don't include a payload hash in the Canonical Request, because
653:      *  when you create a presigned URL, you don't know the payload content
654:      *  because the URL is used to upload an arbitrary payload. Instead, you
655:      *  use a constant string UNSIGNED-PAYLOAD. */
656:     expected_request_payload_hash = AWS4_UNSIGNED_PAYLOAD_HASH;
657:   }
658: 
659:   return expected_request_payload_hash;
660: }
661: 
662: static inline bool is_traditional_v4_unsigned_payload(const char* const exp_payload_hash)
663: {
664:   return boost::equals(exp_payload_hash, AWS4_UNSIGNED_PAYLOAD_HASH);
665: }
666: 
667: static inline bool is_v4_payload_unsigned_chunked(const char* const exp_payload_hash)
668: {
669:   return boost::equals(exp_payload_hash, AWS4_STREAMING_UNSIGNED_PAYLOAD_TRAILER);
670: }
671: 
672: static inline bool is_v4_payload_unsigned(const char* const exp_payload_hash)
673: {
674:   return boost::contains(exp_payload_hash, "UNSIGNED-PAYLOAD");
675: }
676: 
677: static inline bool have_checksum_trailer(const char* const exp_payload_hash)
678: {
679:   return boost::algorithm::ends_with(exp_payload_hash, "TRAILER");
680: }
681: 
682: static inline bool expect_trailer_signature(const char* const exp_payload_hash)
683: {
684:   return boost::equals(exp_payload_hash, AWS4_STREAMING_HMAC_SHA256_PAYLOAD_TRAILER);
685: }
