31: /* Load information about identity that will be used by RGWOp to authorize
32:  * any operation that comes from an authenticated user. */
33: class Identity {
34: public:
35:   typedef std::map<std::string, int> aclspec_t;
36: 
37:   virtual ~Identity() = default;
38: 
39:   /* Return the ACLOwner for resources created by this identity. */
40:   virtual ACLOwner get_aclowner() const = 0;
41: 
42:   /* Translate the ACL provided in @aclspec into concrete permission set that
43:    * can be used during the authorization phase (RGWOp::verify_permission).
44:    * On error throws rgw::auth::Exception storing the reason.
45:    *
46:    * NOTE: an implementation is responsible for giving the real semantic to
47:    * the items in @aclspec. That is, their meaning may depend on particular
48:    * applier that is being used. */
49:   virtual uint32_t get_perms_from_aclspec(const DoutPrefixProvider* dpp, const aclspec_t& aclspec) const = 0;
50: 
51:   /* Verify whether a given identity *can be treated as* an admin of rgw_owner
52:   * specified in @o. On error throws rgw::auth::Exception storing the reason. */
53:   virtual bool is_admin_of(const rgw_owner& o) const = 0;
54: 
55:   /* Verify whether a given identity is the rgw_owner specified in @o.
56:    * On internal error throws rgw::auth::Exception storing the reason. */
57:   virtual bool is_owner_of(const rgw_owner& o) const = 0;
58: 
59:   /* Return the permission mask that is used to narrow down the set of
60:    * operations allowed for a given identity. This method reflects the idea
61:    * of subuser tied to RGWUserInfo. On  error throws rgw::auth::Exception
62:    * with the reason. */
63:   virtual uint32_t get_perm_mask() const = 0;
64: 
65:   virtual bool is_anonymous() const {
66:     /* If the identity owns the anonymous account (rgw_user), it's considered
67:      * the anonymous identity. On error throws rgw::auth::Exception storing
68:      * the reason. */
69:     return is_owner_of(rgw_user(RGW_USER_ANON_ID));
70:   }
71: 
72:   virtual void to_str(std::ostream& out) const = 0;
73: 
74:   /* Verify whether a given identity corresponds to an identity in the
75:      provided set */
76:   virtual bool is_identity(const Principal& p) const = 0;
77: 
78:   /* Identity Type: RGW/ LDAP/ Keystone */
79:   virtual uint32_t get_identity_type() const = 0;
80: 
81:   /* Name of Account */
82:   virtual std::string get_acct_name() const = 0;
83: 
84:   /* Subuser of Account */
85:   virtual std::string get_subuser() const = 0;
86: 
87:   /* Identity's tenant namespace */
88:   virtual const std::string& get_tenant() const = 0;
89: 
90:   /* Return the identity's account info if present */
91:   virtual const std::optional<RGWAccountInfo>& get_account() const = 0;
92: 
93:   /* write any auth-specific fields that are safe to expose in the ops log */
94:   virtual void write_ops_log_entry(rgw_log_entry& entry) const {};
95: };
