141:    * is legacy. */
142:   virtual void load_acct_info(const DoutPrefixProvider* dpp, RGWUserInfo& user_info) const = 0; /* out */
143: 
144:   /* Apply any changes to request state. This method will be most useful for
145:    * TempURL of Swift API. */
146:   virtual void modify_request_state(const DoutPrefixProvider* dpp, req_state* s) const {}      /* in/out */
