150: /* Interface class for completing the two-step authentication process.
151:  * Completer provides the second step - the complete() method that should
152:  * be called after Engine::authenticate() but before *committing* results
153:  * of an RGWOp (or sending a response in the case of non-mutating ops).
154:  *
155:  * The motivation driving the interface is to address those authentication
156:  * schemas that require message integrity verification *without* in-memory
157:  * data buffering. Typical examples are AWS Auth v4 and the auth mechanism
158:  * of browser uploads facilities both in S3 and Swift APIs (see RGWPostObj).
159:  * The workflow of request from the authentication point-of-view does look
160:  * like following one:
161:  *  A. authenticate (Engine::authenticate),
162:  *  B. authorize (see RGWOp::verify_permissions),
163:  *  C. execute-prepare (init potential data modifications),
164:  *  D. authenticate-complete - (Completer::complete),
165:  *  E. execute-commit - commit the modifications from point C. */
166: class Completer {
167: public:
168:   /* It's expected that Completers would tend to implement many interfaces
169:    * and be used not only in req_state::auth::completer. Ref counting their
170:    * instances would be helpful. */
171:   typedef std::shared_ptr<Completer> cmplptr_t;
172: 
173:   virtual ~Completer() = default;
174: 
175:   /* Complete the authentication process. Return boolean indicating whether
176:    * the completion succeeded. On error throws rgw::auth::Exception storing
177:    * the reason. */
178:   virtual bool complete() = 0;
179: 
180:   /* Apply any changes to request state. The initial use case was injecting
181:    * the AWSv4 filter over rgw::io::RestfulClient in req_state. */
182:   virtual void modify_request_state(const DoutPrefixProvider* dpp, req_state* s) = 0;     /* in/out */
183: };
