186: /* Interface class for authentication backends (auth engines) in RadosGW.
187:  *
188:  * An engine is supposed only to authenticate (not authorize!) requests
189:  * basing on their req_state and - if access has been granted - provide
190:  * an upper layer with:
191:  *  - rgw::auth::IdentityApplier to commit all changes to the request state as
192:  *    well as to the RADOS store (creating an account, synchronizing
193:  *    user-related information with external databases and so on).
194:  *  - rgw::auth::Completer (optionally) to finish the authentication
195:  *    of the request. Typical use case is verifying message integrity
196:  *    in AWS Auth v4 and browser uploads (RGWPostObj).
197:  *
198:  * Both of them are supposed to be wrapped in Engine::AuthResult.
199:  *
200:  * The authentication process consists of two steps:
201:  *  - Engine::authenticate() which should be called before *initiating*
202:  *    any modifications to RADOS store that are related to an operation
203:  *    a client wants to perform (RGWOp::execute).
204:  *  - Completer::complete() supposed to be called, if completer has been
205:  *    returned, after the authenticate() step but before *committing*
206:  *    those modifications or sending a response (RGWOp::complete).
207:  *
208:  * An engine outlives both Applier and Completer. It's intended to live
209:  * since RadosGW's initialization and handle multiple requests till
210:  * a reconfiguration.
211:  *
212:  * Auth engine MUST NOT make any changes to req_state nor RADOS store.
213:  * This is solely an Applier's responsibility!
214:  *
215:  * Separation between authentication and global state modification has
216:  * been introduced because many auth engines are orthogonal to appliers
217:  * and thus they can be decoupled. Additional motivation is to clearly
218:  * distinguish all portions of code modifying data structures. */
219: class Engine {
220: public:
221:   virtual ~Engine() = default;
222: 
223:   class AuthResult {
224:     struct rejection_mark_t {};
225:     bool is_rejected = false;
226:     int reason = 0;
227: 
228:     std::pair<IdentityApplier::aplptr_t, Completer::cmplptr_t> result_pair;
229: 
230:     explicit AuthResult(const int reason)
231:       : reason(reason) {
232:     }
233: 
234:     AuthResult(rejection_mark_t&&, const int reason)
235:       : is_rejected(true),
236:         reason(reason) {
237:     }
238: 
239:     /* Allow only the reasonable combinations - returning just Completer
240:      * without accompanying IdentityApplier is strictly prohibited! */
241:     explicit AuthResult(IdentityApplier::aplptr_t&& applier)
242:       : result_pair(std::move(applier), nullptr) {
243:     }
244: 
245:     AuthResult(IdentityApplier::aplptr_t&& applier,
246:                Completer::cmplptr_t&& completer)
247:       : result_pair(std::move(applier), std::move(completer)) {
248:     }
249: 
250:   public:
251:     enum class Status {
252:       /* Engine doesn't grant the access but also doesn't reject it. */
253:       DENIED,
254: 
255:       /* Engine successfully authenticated requester. */
256:       GRANTED,
257: 
258:       /* Engine strictly indicates that a request should be rejected
259:        * without trying any further engine. */
260:       REJECTED
261:     };
262: 
263:     Status get_status() const {
264:       if (is_rejected) {
265:         return Status::REJECTED;
266:       } else if (! result_pair.first) {
267:         return Status::DENIED;
268:       } else {
269:         return Status::GRANTED;
270:       }
271:     }
272: 
273:     int get_reason() const {
274:       return reason;
275:     }
276: 
277:     IdentityApplier::aplptr_t get_applier() {
278:       return std::move(result_pair.first);
279:     }
280: 
281:     Completer::cmplptr_t&& get_completer() {
282:       return std::move(result_pair.second);
283:     }
284: 
285:     static AuthResult reject(const int reason = -EACCES) {
286:       return AuthResult(rejection_mark_t(), reason);
287:     }
288: 
289:     static AuthResult deny(const int reason = -EACCES) {
290:       return AuthResult(reason);
291:     }
292: 
293:     static AuthResult grant(IdentityApplier::aplptr_t&& applier) {
294:       return AuthResult(std::move(applier));
295:     }
296: 
297:     static AuthResult grant(IdentityApplier::aplptr_t&& applier,
298:                             Completer::cmplptr_t&& completer) {
299:       return AuthResult(std::move(applier), std::move(completer));
300:     }
301:   };
302: 
303:   using result_t = AuthResult;
304: 
305:   /* Get name of the auth engine. */
306:   virtual const char* get_name() const noexcept = 0;
307: 
308:   /* Throwing method for identity verification. When the check is positive
309:    * an implementation should return Engine::result_t containing:
310:    *  - a non-null pointer to an object conforming the Applier interface.
311:    *    Otherwise, the authentication is treated as failed.
312:    *  - a (potentially null) pointer to an object conforming the Completer
313:    *    interface.
314:    *
315:    * On error throws rgw::auth::Exception containing the reason. */
316:   virtual result_t authenticate(const DoutPrefixProvider* dpp, const req_state* s, optional_yield y) const = 0;
317: };
