328: /* Abstract class for stacking sub-engines to expose them as a single
329:  * Engine. It is responsible for ordering its sub-engines and managing
330:  * fall-backs between them. Derivative is supposed to encapsulate engine
331:  * instances and add them using the add_engine() method in the order it
332:  * wants to be tried during the call to authenticate().
333:  *
334:  * Each new Strategy should be exposed to StrategyRegistry for handling
335:  * the dynamic reconfiguration. */
336: class Strategy : public Engine {
337: public:
338:   /* Specifiers controlling what happens when an associated engine fails.
339:    * The names and semantic has been borrowed mostly from libpam. */
340:   enum class Control {
341:     /* Failure of an engine injected with the REQUISITE specifier aborts
342:      * the strategy's authentication process immediately. No other engine
343:      * will be tried. */
344:     REQUISITE,
345: 
346:     /* Success of an engine injected with the SUFFICIENT specifier ends
347:      * strategy's authentication process successfully. However, denying
348:      * doesn't abort it -- there will be fall-back to following engine
349:      * if the one that failed wasn't the last one. */
350:     SUFFICIENT,
351: 
352:     /* Like SUFFICIENT with the exception that on failure the reason code
353:      * is not overridden. Instead, it's taken directly from the last tried
354:      * non-FALLBACK engine. If there was no previous non-FALLBACK engine
355:      * in a Strategy, then the result_t::deny(reason = -EACCES) is used. */
356:     FALLBACK,
357:   };
358: 
359:   Engine::result_t authenticate(const DoutPrefixProvider* dpp, const req_state* s, optional_yield y) const override final;
360: 
361:   bool is_empty() const {
362:     return auth_stack.empty();
363:   }
364: 
365:   static int apply(const DoutPrefixProvider* dpp, const Strategy& auth_strategy, req_state* s, optional_yield y) noexcept;
366: 
367: private:
368:   /* Using the reference wrapper here to explicitly point out we are not
369:    * interested in storing nulls while preserving the dynamic polymorphism. */
370:   using stack_item_t = std::pair<std::reference_wrapper<const Engine>,
371:                                  Control>;
372:   std::vector<stack_item_t> auth_stack;
373: 
374: protected:
375:   void add_engine(Control ctrl_flag, const Engine& engine) noexcept;
376: };
