62: /*
63:  * ?get the canonical amazon-style header for something?
64:  */
65: 
66: template<typename M>
67: static std::string
68: get_canon_amz_hdrs(const M& map)
69: {
70:   size_t length = 0;
71:   std::string dest; // why dest?
72:   std::for_each(map.begin(), map.end(), [&length] (const auto& elt) -> void {
73:     length += elt.first.size() + sarrlen(":") + elt.second.size() +
74:       sarrlen("\n");
75:   });
76:   dest.reserve(length);
77: 
78:   for (const auto& kv : map) {
79:     dest.append(kv.first);
80:     dest.append(":");
81:     dest.append(kv.second);
82:     dest.append("\n");
83:   }
84: 
85:   return dest;
86: } /* get_canon_amz_hdrs */
87: 
88: /*
89:  * ?get the canonical representation of the object's location
90:  */
91: static std::string
92: get_canon_resource(const DoutPrefixProvider *dpp, const char* const request_uri,
93:                    const std::map<std::string, std::string>& sub_resources)
94: {
95:   std::string dest;
96: 
97:   if (request_uri) {
98:     dest.append(request_uri);
99:   }
100: 
101:   bool initial = true;
102:   for (const auto& subresource : signed_subresources) {
103:     const auto iter = sub_resources.find(subresource);
104:     if (iter == std::end(sub_resources)) {
105:       continue;
106:     }
107:     
108:     if (initial) {
109:       dest.append("?");
110:       initial = false;
111:     } else {
112:       dest.append("&");
113:     }
114: 
115:     dest.append(iter->first);
116:     if (! iter->second.empty()) {
117:       dest.append("=");
118:       dest.append(iter->second);
119:     }
120:   }
121: 
122:   ldpp_dout(dpp, 10) << "get_canon_resource(): dest=" << dest << dendl;
123:   return dest;
124: }
