126: /*
127:  * get the header authentication  information required to
128:  * compute a request's signature
129:  */
130: void rgw_create_s3_canonical_header(
131:   const DoutPrefixProvider *dpp,
132:   const char* const method,
133:   const char* const content_md5,
134:   const char* const content_type,
135:   const char* const date,
136:   const meta_map_t& meta_map,
137:   const meta_map_t& qs_map,
138:   const char* const request_uri,
139:   const std::map<std::string, std::string>& sub_resources,
140:   std::string& dest_str)
141: {
142:   std::string dest;
143: 
144:   if (method) {
145:     dest = method;
146:   }
147:   dest.append("\n");
148:   
149:   if (content_md5) {
150:     dest.append(content_md5);
151:   }
152:   dest.append("\n");
153: 
154:   if (content_type) {
155:     dest.append(content_type);
156:   }
157:   dest.append("\n");
158: 
159:   if (date) {
160:     dest.append(date);
161:   }
162:   dest.append("\n");
163: 
164:   dest.append(get_canon_amz_hdrs(meta_map));
165:   dest.append(get_canon_amz_hdrs(qs_map));
166:   dest.append(get_canon_resource(dpp, request_uri, sub_resources));
167: 
168:   dest_str = dest;
169: }
