171: static inline bool is_base64_for_content_md5(unsigned char c) {
172:   return (isalnum(c) || isspace(c) || (c == '+') || (c == '/') || (c == '='));
173: }
174: 
175: static inline void get_v2_qs_map(const req_info& info,
176: 				 meta_map_t& qs_map) {
177:   const auto& params = const_cast<RGWHTTPArgs&>(info.args).get_params();
178:   for (const auto& elt : params) {
179:     std::string k = boost::algorithm::to_lower_copy(elt.first);
180:     if (k.find("x-amz-meta-") == /* offset */ 0) {
181:       rgw_add_amz_meta_header(qs_map, k, elt.second);
182:     }
183:     if (k == "x-amz-security-token") {
184:       qs_map[k] = elt.second;
185:     }
186:   }
187: }
