189: /*
190:  * get the header authentication  information required to
191:  * compute a request's signature
192:  */
193: bool rgw_create_s3_canonical_header(const DoutPrefixProvider *dpp,
194:                                     const req_info& info,
195:                                     utime_t* const header_time,
196:                                     std::string& dest,
197:                                     const bool qsr)
198: {
199:   const char* const content_md5 = info.env->get("HTTP_CONTENT_MD5");
200:   if (content_md5) {
201:     for (const char *p = content_md5; *p; p++) {
202:       if (!is_base64_for_content_md5(*p)) {
203:         ldpp_dout(dpp, 0) << "NOTICE: bad content-md5 provided (not base64),"
204:                 << " aborting request p=" << *p << " " << (int)*p << dendl;
205:         return false;
206:       }
207:     }
208:   }
209: 
210:   const char *content_type = info.env->get("CONTENT_TYPE");
211: 
212:   std::string date;
213:   meta_map_t qs_map;
214: 
215:   if (qsr) {
216:     get_v2_qs_map(info, qs_map); // handle qs metadata
217:     date = info.args.get("Expires");
218:   } else {
219:     const char *str = info.env->get("HTTP_X_AMZ_DATE");
220:     const char *req_date = str;
221:     if (str == NULL) {
222:       req_date = info.env->get("HTTP_DATE");
223:       if (!req_date) {
224:         ldpp_dout(dpp, 0) << "NOTICE: missing date for auth header" << dendl;
225:         return false;
226:       }
227:       date = req_date;
228:     }
229: 
230:     if (header_time) {
231:       struct tm t;
232:       uint32_t ns = 0;
233:       if (!parse_rfc2616(req_date, &t) && !parse_iso8601(req_date, &t, &ns, false)) {
234:         ldpp_dout(dpp, 0) << "NOTICE: failed to parse date <" << req_date << "> for auth header" << dendl;
235:         return false;
236:       }
237:       if (t.tm_year < 70) {
238:         ldpp_dout(dpp, 0) << "NOTICE: bad date (predates epoch): " << req_date << dendl;
239:         return false;
240:       }
241:       *header_time = utime_t(internal_timegm(&t), 0);
242:       *header_time -= t.tm_gmtoff;
243:     }
244:   }
245: 
246:   const auto& meta_map = info.x_meta_map;
247:   const auto& sub_resources = info.args.get_sub_resources();
248: 
249:   std::string request_uri;
250:   if (info.effective_uri.empty()) {
251:     request_uri = info.request_uri;
252:   } else {
253:     request_uri = info.effective_uri;
254:   }
255: 
256:   rgw_create_s3_canonical_header(dpp, info.method, content_md5, content_type,
257:                                  date.c_str(), meta_map, qs_map,
258: 				 request_uri.c_str(), sub_resources, dest);
259:   return true;
260: }
