363: template<std::size_t ExpectedStrNum>
364: boost::container::small_vector<std::string_view, ExpectedStrNum>
365: get_str_vec(const std::string_view& str, const char* const delims)
366: {
367:   boost::container::small_vector<std::string_view, ExpectedStrNum> str_vec;
368: 
369:   size_t pos = 0;
370:   std::string_view token;
371:   while (pos < str.size()) {
372:     if (get_next_token(str, pos, delims, token)) {
373:       if (token.size() > 0) {
374:         str_vec.push_back(token);
375:       }
376:     }
377:   }
378: 
379:   return str_vec;
380: }
