390: static inline int parse_v4_auth_header(const req_info& info,               /* in */
391:                                        std::string_view& credential,     /* out */
392:                                        std::string_view& signedheaders,  /* out */
393:                                        std::string_view& signature,      /* out */
394:                                        std::string_view& date,           /* out */
395:                                        std::string_view& sessiontoken,   /* out */
396:                                        const DoutPrefixProvider *dpp)
397: {
398:   std::string_view input(info.env->get("HTTP_AUTHORIZATION", ""));
399:   try {
400:     input = input.substr(::strlen(AWS4_HMAC_SHA256_STR) + 1);
401:   } catch (std::out_of_range&) {
402:     /* We should never ever run into this situation as the presence of
403:      * AWS4_HMAC_SHA256_STR had been verified earlier. */
404:     ldpp_dout(dpp, 10) << "credentials string is too short" << dendl;
405:     return -EINVAL;
406:   }
407: 
408:   std::map<std::string_view, std::string_view> kv;
409:   for (const auto& s : get_str_vec<4>(input, ",")) {
410:     const auto parsed_pair = parse_key_value(s);
411:     if (parsed_pair) {
412:       kv[parsed_pair->first] = parsed_pair->second;
413:     } else {
414:       ldpp_dout(dpp, 10) << "NOTICE: failed to parse auth header (s=" << s << ")"
415:                << dendl;
416:       return -EINVAL;
417:     }
418:   }
419: 
420:   static const std::array<std::string_view, 3> required_keys = {
421:     "Credential",
422:     "SignedHeaders",
423:     "Signature"
424:   };
425: 
426:   /* Ensure that the presigned required keys are really there. */
427:   for (const auto& k : required_keys) {
428:     if (kv.find(k) == std::end(kv)) {
429:       ldpp_dout(dpp, 10) << "NOTICE: auth header missing key: " << k << dendl;
430:       return -EINVAL;
431:     }
432:   }
433: 
434:   credential = kv["Credential"];
435:   signedheaders = kv["SignedHeaders"];
436:   signature = kv["Signature"];
437: 
438:   /* sig hex str */
439:   ldpp_dout(dpp, 10) << "v4 signature format = " << signature << dendl;
440: 
441:   /* ------------------------- handle x-amz-date header */
442: 
443:   /* grab date */
444: 
445:   const char *d = info.env->get("HTTP_X_AMZ_DATE");
446: 
447:   struct tm t;
448:   if (unlikely(d == NULL)) {
449:     d = info.env->get("HTTP_DATE");
450:   }
451:   if (!d || !parse_iso8601(d, &t, NULL, false)) {
452:     ldpp_dout(dpp, 10) << "error reading date via http_x_amz_date and http_date" << dendl;
453:     return -EACCES;
454:   }
455:   date = d;
456: 
457:   if (!is_time_skew_ok(internal_timegm(&t))) {
458:     return -ERR_REQUEST_TIME_SKEWED;
459:   }
460: 
461:   auto token = info.env->get_optional("HTTP_X_AMZ_SECURITY_TOKEN");
462:   if (token) {
463:     sessiontoken = *token;
464:   }
465: 
466:   return 0;
467: }
