538: int parse_v4_credentials(const req_info& info,                     /* in */
539: 			 std::string_view& access_key_id,        /* out */
540: 			 std::string_view& credential_scope,     /* out */
541: 			 std::string_view& signedheaders,        /* out */
542: 			 std::string_view& signature,            /* out */
543: 			 std::string_view& date,                 /* out */
544: 			 std::string_view& session_token,        /* out */
545: 			 const bool using_qs,                    /* in */
546:                          const DoutPrefixProvider *dpp)
547: {
548:   std::string_view credential;
549:   int ret;
550:   if (using_qs) {
551:     ret = parse_v4_query_string(info, credential, signedheaders,
552:                                 signature, date, session_token);
553:   } else {
554:     ret = parse_v4_auth_header(info, credential, signedheaders,
555:                                signature, date, session_token, dpp);
556:   }
557: 
558:   if (ret < 0) {
559:     return ret;
560:   }
561: 
562:   /* access_key/YYYYMMDD/region/service/aws4_request */
563:   ldpp_dout(dpp, 10) << "v4 credential format = " << credential << dendl;
564: 
565:   if (std::count(credential.begin(), credential.end(), '/') != 4) {
566:     return -EINVAL;
567:   }
568: 
569:   /* credential must end with 'aws4_request' */
570:   if (credential.find("aws4_request") == std::string::npos) {
571:     return -EINVAL;
572:   }
573: 
574:   /* grab access key id */
575:   const size_t pos = credential.find("/");
576:   access_key_id = credential.substr(0, pos);
577:   ldpp_dout(dpp, 10) << "access key id = " << access_key_id << dendl;
578: 
579:   /* grab credential scope */
580:   credential_scope = credential.substr(pos + 1);
581:   ldpp_dout(dpp, 10) << "credential scope = " << credential_scope << dendl;
582: 
583:   return 0;
584: }
