586: string gen_v4_scope(const ceph::real_time& timestamp,
587:                     const string& region,
588:                     const string& service)
589: {
590: 
591:   auto sec = real_clock::to_time_t(timestamp);
592: 
593:   struct tm bt;
594:   gmtime_r(&sec, &bt);
595: 
596:   auto year = 1900 + bt.tm_year;
597:   auto mon = bt.tm_mon + 1;
598:   auto day = bt.tm_mday;
599: 
600:   return fmt::format(FMT_STRING("{:d}{:02d}{:02d}/{:s}/{:s}/aws4_request"),
601:                      year, mon, day, region, service);
602: }
