604: std::string get_v4_canonical_qs(const req_info& info, const bool using_qs)
605: {
606:   const std::string *params = &info.request_params;
607:   std::string copy_params;
608:   if (params->empty()) {
609:     /* Optimize the typical flow. */
610:     return std::string();
611:   }
612:   if (params->find_first_of('+') != std::string::npos) {
613:     copy_params = *params;
614:     boost::replace_all(copy_params, "+", "%20");
615:     params = &copy_params;
616:   }
617: 
618:   /* Handle case when query string exists. Step 3 described in: http://docs.
619:    * aws.amazon.com/general/latest/gr/sigv4-create-canonical-request.html */
620:   std::multimap<std::string, std::string> canonical_qs_map;
621:   for (const auto& s : get_str_vec<5>(*params, "&")) {
622:     std::string_view key, val;
623:     const auto parsed_pair = parse_key_value(s);
624:     if (parsed_pair) {
625:       std::tie(key, val) = *parsed_pair;
626:     } else {
627:       /* Handling a parameter without any value (even the empty one). That's
628:        * it, we've encountered something like "this_param&other_param=val"
629:        * which is used by S3 for subresources. */
630:       key = s;
631:     }
632: 
633:     if (using_qs && boost::iequals(key, "X-Amz-Signature")) {
634:       /* Preserving the original behaviour of get_v4_canonical_qs() here. */
635:       continue;
636:     }
637: 
638:     // while awsv4 specs ask for all slashes to be encoded, s3 itself is relaxed
639:     // in its implementation allowing non-url-encoded slashes to be present in
640:     // presigned urls for instance
641:     canonical_qs_map.insert({{aws4_uri_recode(key, true), aws4_uri_recode(val, true)}});
642:   }
643: 
644:   /* Thanks to the early exist we have the guarantee that canonical_qs_map has
645:    * at least one element. */
646:   auto iter = std::begin(canonical_qs_map);
647:   std::string canonical_qs;
648:   canonical_qs.append(iter->first)
649:               .append("=", sarrlen("="))
650:               .append(iter->second);
651: 
652:   for (iter++; iter != std::end(canonical_qs_map); iter++) {
653:     canonical_qs.append("&", sarrlen("&"))
654:                 .append(iter->first)
655:                 .append("=", sarrlen("="))
656:                 .append(iter->second);
657:   }
658: 
659:   return canonical_qs;
660: }
