662: static void add_v4_canonical_params_from_map(const map<string, string>& m,
663:                                         std::map<string, string> *result,
664:                                         bool is_non_s3_op)
665: {
666:   for (auto& entry : m) {
667:     const auto& key = entry.first;
668:     if (key.empty() || (is_non_s3_op && key == "PayloadHash")) {
669:       continue;
670:     }
671: 
672:     (*result)[aws4_uri_recode(key, true)] = aws4_uri_recode(entry.second, true);
673:   }
674: }
