833: std::string gen_v4_canonical_headers(const req_info& info,
834:                                      const map<string, string>& extra_headers,
835:                                      string *signed_hdrs)
836: {
837:   std::map<std::string, std::string> canonical_hdrs_map;
838:   for (auto& entry : info.env->get_map()) {
839:     handle_header(entry.first, entry.second, &canonical_hdrs_map);
840:   }
841:   for (auto& entry : extra_headers) {
842:     handle_header(entry.first, entry.second, &canonical_hdrs_map);
843:   }
844: 
845:   std::string canonical_hdrs;
846:   signed_hdrs->clear();
847:   for (const auto& header : canonical_hdrs_map) {
848:     const auto& name = header.first;
849:     std::string value = header.second;
850:     boost::trim_all<std::string>(value);
851: 
852:     if (!signed_hdrs->empty()) {
853:       signed_hdrs->append(";");
854:     }
855:     signed_hdrs->append(name);
856: 
857:     canonical_hdrs.append(name.data(), name.length())
858:                   .append(":", sarrlen(":"))
859:                   .append(value)
860:                   .append("\n", sarrlen("\n"));
861:   }
862: 
863:   return canonical_hdrs;
864: }
