866: /*
867:  * create canonical request for signature version 4
868:  *
869:  * http://docs.aws.amazon.com/general/latest/gr/sigv4-create-canonical-request.html
870:  */
871: sha256_digest_t
872: get_v4_canon_req_hash(CephContext* cct,
873:                       const std::string_view& http_verb,
874:                       const std::string& canonical_uri,
875:                       const std::string& canonical_qs,
876:                       const std::string& canonical_hdrs,
877:                       const std::string_view& signed_hdrs,
878:                       const std::string_view& request_payload_hash,
879:                       const DoutPrefixProvider *dpp)
880: {
881:   ldpp_dout(dpp, 10) << "payload request hash = " << request_payload_hash << dendl;
882: 
883:   const auto canonical_req = string_join_reserve("\n",
884:     http_verb,
885:     canonical_uri,
886:     canonical_qs,
887:     canonical_hdrs,
888:     signed_hdrs,
889:     request_payload_hash);
890: 
891:   const auto canonical_req_hash = calc_hash_sha256(canonical_req);
892: 
893:   using sanitize = rgw::crypt_sanitize::log_content;
894:   ldpp_dout(dpp, 10) << "canonical request = " << sanitize{canonical_req} << dendl;
895:   ldpp_dout(dpp, 10) << "canonical request hash = "
896:                  << canonical_req_hash << dendl;
897: 
898:   return canonical_req_hash;
899: }
