901: /*
902:  * create string to sign for signature version 4
903:  *
904:  * http://docs.aws.amazon.com/general/latest/gr/sigv4-create-string-to-sign.html
905:  */
906: AWSEngine::VersionAbstractor::string_to_sign_t
907: get_v4_string_to_sign(CephContext* const cct,
908:                       const std::string_view& algorithm,
