931: static inline std::tuple<std::string_view,            /* date */
932:                          std::string_view,            /* region */
933:                          std::string_view>            /* service */
934: parse_cred_scope(std::string_view credential_scope)
935: {
936:   /* date cred */
937:   size_t pos = credential_scope.find("/");
938:   const auto date_cs = credential_scope.substr(0, pos);
939:   credential_scope = credential_scope.substr(pos + 1);
940: 
941:   /* region cred */
942:   pos = credential_scope.find("/");
943:   const auto region_cs = credential_scope.substr(0, pos);
944:   credential_scope = credential_scope.substr(pos + 1);
945: 
946:   /* service cred */
947:   pos = credential_scope.find("/");
948:   const auto service_cs = credential_scope.substr(0, pos);
949: 
950:   return std::make_tuple(date_cs, region_cs, service_cs);
951: }
