953: static inline std::vector<unsigned char>
954: transform_secret_key(const std::string_view& secret_access_key)
955: {
956:   /* TODO(rzarzynski): switch to constexpr when C++14 becomes available. */
957:   static const std::initializer_list<unsigned char> AWS4 { 'A', 'W', 'S', '4' };
958: 
959:   /* boost::container::small_vector might be used here if someone wants to
960:    * optimize out even more dynamic allocations. */
961:   std::vector<unsigned char> secret_key_utf8;
962:   secret_key_utf8.reserve(AWS4.size() + secret_access_key.size());
963:   secret_key_utf8.assign(AWS4);
964: 
965:   for (const auto c : secret_access_key) {
966:     std::array<unsigned char, MAX_UTF8_SZ> buf;
967:     const size_t n = encode_utf8(c, buf.data());
968:     secret_key_utf8.insert(std::end(secret_key_utf8),
969:                            std::begin(buf), std::begin(buf) + n);
970:   }
971: 
972:   return secret_key_utf8;
973: }
