1004: /*
1005:  * calculate the AWS signature version 4
1006:  *
1007:  * http://docs.aws.amazon.com/general/latest/gr/sigv4-calculate-signature.html
1008:  *
1009:  * srv_signature_t is an alias over Ceph's basic_sstring. We're using
1010:  * it to keep everything within the stack boundaries instead of doing
1011:  * dynamic allocations.
1012:  */
1013: AWSEngine::VersionAbstractor::server_signature_t
1014: get_v4_signature(const std::string_view& credential_scope,
1015:                  CephContext* const cct,
1016:                  const std::string_view& secret_key,
1017:                  const AWSEngine::VersionAbstractor::string_to_sign_t& string_to_sign,
1018:                  const DoutPrefixProvider *dpp)
1019: {
1020:   auto signing_key = get_v4_signing_key(cct, credential_scope, secret_key, dpp);
1021: 
1022:   /* The server-side generated digest for comparison. */
1023:   const auto digest = calc_hmac_sha256(signing_key, string_to_sign);
1024: 
1025:   /* TODO(rzarzynski): I would love to see our sstring having reserve() and
1026:    * the non-const data() variant like C++17's std::string. */
1027:   using srv_signature_t = AWSEngine::VersionAbstractor::server_signature_t;
1028:   srv_signature_t signature(srv_signature_t::initialized_later(),
1029:                             digest.SIZE * 2);
1030:   buf_to_hex(digest.v, digest.SIZE, signature.begin());
1031: 
1032:   ldpp_dout(dpp, 10) << "generated signature = " << signature << dendl;
1033: 
1034:   return signature;
1035: }
1036: 
1037: AWSEngine::VersionAbstractor::server_signature_t
1038: get_v2_signature(CephContext* const cct,
1039:                  const std::string& secret_key,
1040:                  const AWSEngine::VersionAbstractor::string_to_sign_t& string_to_sign)
1041: {
1042:   if (secret_key.empty()) {
1043:     throw -EINVAL;
1044:   }
1045: 
1046:   const auto digest = calc_hmac_sha1(secret_key, string_to_sign);
1047: 
1048:   /* 64 is really enough */;
1049:   char buf[64];
1050:   const int ret = ceph_armor(std::begin(buf),
1051:                              std::begin(buf) + 64,
1052:                              reinterpret_cast<const char *>(digest.v),
1053:                              reinterpret_cast<const char *>(digest.v + digest.SIZE));
1054:   if (ret < 0) {
1055:     ldout(cct, 10) << "ceph_armor failed" << dendl;
1056:     throw ret;
1057:   } else {
1058:     buf[ret] = '\0';
1059:     using srv_signature_t = AWSEngine::VersionAbstractor::server_signature_t;
1060:     return srv_signature_t(buf, ret);
1061:   }
1062: }
