1079: /* AWSv4 completers begin. */
1080: std::pair<AWSv4ComplMulti::ChunkMeta, size_t /* consumed */>
1081: AWSv4ComplMulti::ChunkMeta::create_next(CephContext* const cct,
1082:                                         ChunkMeta&& old,
1083:                                         const char* const metabuf,
1084:                                         const size_t metabuf_len,
1085: 					uint32_t flags)
1086: {
1087:   std::string_view metastr(metabuf, metabuf_len);
1088: 
1089:   bool unsigned_chunked = flags & AWSv4ComplMulti::FLAG_UNSIGNED_CHUNKED;
1090:   bool expect_chunk_signature = !unsigned_chunked; // for now
1091: 
1092:   ldout(cct, 20) << "AWSv4ComplMulti::create_next() old.cnt: " << old.cnt << dendl;
1093: 
1094:   char* data_field_end;
1095:   /* strtoull ignores the "\r\n" sequence after each non-first chunk. */
1096:   const size_t data_length = std::strtoull(metabuf, &data_field_end, 16);
1097:   if (data_length == 0 && data_field_end == metabuf) {
1098:     ldout(cct, 20) << "AWSv4ComplMulti: cannot parse the data size"
1099:                    << dendl;
1100:     throw rgw::io::Exception(EINVAL, std::system_category());
1101:   }
1102: 
1103:   if (expect_chunk_signature) {
1104: 
1105:     /* traditional parse looks for
1106:        string(IntHexBase(chunk-size)) + ";chunk-signature=" + signature + \r\n + chunk-data + \r\n
1107:        cf. https://docs.aws.amazon.com/AmazonS3/latest/API/sigv4-streaming.html */
1108: 
1109:     const size_t semicolon_pos = metastr.find(";");
1110:     if (semicolon_pos == std::string_view::npos) {
1111:       ldout(cct, 20) << "AWSv4ComplMulti cannot find the ';' separator"
1112: 		     << dendl;
1113:       throw rgw::io::Exception(EINVAL, std::system_category());
1114:     }
1115: 
1116:     /* Parse the chunk_signature=... part. */
1117:     const auto signature_part = metastr.substr(semicolon_pos + 1);
1118:     const size_t eq_sign_pos = signature_part.find("=");
1119:     if (eq_sign_pos == std::string_view::npos) {
1120:       ldout(cct, 20) << "AWSv4ComplMulti: cannot find the '=' separator"
1121:                      << dendl;
1122:       throw rgw::io::Exception(EINVAL, std::system_category());
1123:     }
1124: 
1125:     /* OK, we have at least the beginning of a signature. */
1126:     const size_t data_sep_pos = signature_part.find("\r\n");
1127:     if (data_sep_pos == std::string_view::npos) {
1128:       ldout(cct, 20) << "AWSv4ComplMulti: no new line at signature end"
1129:                      << dendl;
1130:       throw rgw::io::Exception(EINVAL, std::system_category());
1131:     }
1132: 
1133:     const auto signature =
1134:         signature_part.substr(eq_sign_pos + 1, data_sep_pos - 1 - eq_sign_pos);
1135:     if (signature.length() != SIG_SIZE) {
1136:       ldout(cct, 20) << "AWSv4ComplMulti: signature.length() != 64" << dendl;
1137:       throw rgw::io::Exception(EINVAL, std::system_category());
1138:     }
1139: 
1140:     const size_t data_starts_in_stream =
1141:         +semicolon_pos + sarrlen(";") + data_sep_pos + sarrlen("\r\n") +
1142:         old.data_offset_in_stream + old.data_length;
1143: 
1144:     ldout(cct, 20) << "parsed new chunk; signature=" << signature
1145:                    << ", data_length=" << data_length
1146:                    << ", data_starts_in_stream=" << data_starts_in_stream
1147:                    << dendl;
1148: 
1149:     return std::make_pair(
1150: 	     ChunkMeta(data_starts_in_stream, data_length, signature, flags,
1151: 		       ++old.cnt),
1152: 	     semicolon_pos + 83);
1153:   } else {
1154:     /* no-chunk-signature aws-chunked */
1155:     ldout(cct, 20) << "AWSv4ComplMulti: non-signature meta chunk; data_length "
1156: 		   << data_length
1157: 		   << dendl;
1158: 
1159:     /* currently we might see "\r\n20000\r\nreate the directory..." */
1160:     size_t crlf_pos = metastr.find("\r\n");
1161:     if (crlf_pos == 0) [[likely]] {
1162:       crlf_pos = metastr.find("\r\n", 2); // skip to next one
1163:     }
1164:     if (crlf_pos == std::string_view::npos) {
1165:       ldout(cct, 20) << "AWSv4ComplMulti: no new line at expected chunk end"
1166:                      << dendl;
1167:       throw rgw::io::Exception(EINVAL, std::system_category());
1168:     }
1169: 
1170:     const size_t consumed = crlf_pos + sarrlen("\r\n");
1171:     const size_t data_starts_in_stream =
1172:         consumed + old.data_offset_in_stream + old.data_length;
1173:     return std::make_pair(ChunkMeta(data_starts_in_stream, data_length,
1174: 			    "" /* signature */, flags, ++old.cnt),
1175:                           consumed);
1176:   } /* no-signature */
1177: } /* AWSv4ComplMulti::ChunkMeta::create_next */
1178: 
1179: std::string
1180: AWSv4ComplMulti::calc_chunk_signature(const std::string& payload_hash) const
1181: {
1182:   const auto string_to_sign = string_join_reserve("\n",
1183:     AWS4_HMAC_SHA256_PAYLOAD_STR,
1184:     date,
1185:     credential_scope,
1186:     prev_chunk_signature,
1187:     AWS4_EMPTY_PAYLOAD_HASH,
1188:     payload_hash);
1189: 
1190:   ldout(cct(), 20) << "AWSv4ComplMulti: string_to_sign=\n" << string_to_sign
1191:                  << dendl;
1192: 
1193:   /* new chunk signature */
1194:   const auto sig = calc_hmac_sha256(signing_key, string_to_sign);
1195:   /* FIXME(rzarzynski): std::string here is really unnecessary. */
1196:   return sig.to_str();
1197: }
