1199: bool AWSv4ComplMulti::is_signature_mismatched()
1200: {
1201:   /* in streaming unsigned payload, there are no chunk signatures nor trailer
1202:    * signature; there may be a trailing checksum
1203:    *
1204:    * if (flags & FLAG_UNSIGNED_CHUNKED), then we assert chunk_meta.signature.empty(),
1205:    * and conversely
1206:    */
1207:   if (flags & FLAG_UNSIGNED_CHUNKED) {
1208:     return false;
1209:   }
1210: 
1211:   /* The validity of previous chunk can be verified only after getting meta-
1212:    * data of the next one. */
1213:   const auto payload_hash = calc_hash_sha256_restart_stream(&sha256_hash);
1214:   const auto calc_signature = calc_chunk_signature(payload_hash);
1215: 
1216:   if (cct()->_conf->subsys.should_gather(ceph_subsys_rgw, 16)) [[unlikely]] {
1217:     ldout(cct(), 16) << "AWSv4ComplMulti: declared signature="
1218: 		     << chunk_meta.get_signature()
1219: 		     << "\nAWSv4ComplMulti: calculated signature="
1220: 		     << calc_signature << dendl;
1221:     ldout(cct(), 16) << "AWSv4ComplMulti: prev_chunk_signature="
1222: 		     << prev_chunk_signature << dendl;
1223:   }
1224: 
1225:   auto match_signatures = [&]() -> bool {
1226:     /* sentinel case: 0-length chunk, likely chunk 0 */
1227:     if (chunk_meta.get_offset() == 0) [[unlikely]] {
1228:       return chunk_meta.get_signature() == prev_chunk_signature;
1229:     }
1230:     /* all other cases */
1231:     return chunk_meta.get_signature() == calc_signature;
1232:   };
1233: 
1234:   if (! match_signatures()) [[unlikely]] {
1235:     ldout(cct(), 16) << "AWSv4ComplMulti: ERROR: chunk signature mismatch"
1236:                    << dendl;
1237:     return true;
1238:   } else {
1239:     prev_chunk_signature = chunk_meta.get_signature();
1240:     return false;
1241:   }
1242: } /* AWSv4ComplMulti::is_signature_mismatched */
1243: 
1244: AWSv4ComplMulti::ReceiveChunkResult AWSv4ComplMulti::recv_chunk(
1245:   char* const buf, const size_t buf_max, uint32_t cnt, bool& eof)
1246: {
1247:   /* Buffer stores only parsed stream. Raw values reflect the stream
1248:    * we're getting from a client. */
1249:   size_t buf_pos = 0;
1250: 
1251:   ldout(cct(), 20) << "AWSv4ComplMulti::recv_chunk() cnt: " << cnt << dendl;
1252: 
1253:   if (chunk_meta.is_new_chunk_in_stream(stream_pos)) {
1254:     /* Verify signature of the previous chunk. We aren't doing that for new
1255:      * one as the procedure requires calculation of payload hash. This code
1256:      * won't be triggered for the last, zero-length chunk. Instead, it will
1257:      * be checked in the complete() method.  */
1258:     if (stream_pos >= ChunkMeta::META_MAX_SIZE && is_signature_mismatched()) {
1259:       throw rgw::io::Exception(ERR_SIGNATURE_NO_MATCH, std::system_category());
1260:     }
1261: 
1262:     /* We don't have metadata for this range. This means a new chunk, so we
1263:      * need to parse a fresh portion of the stream. Let's start. */
1264:     size_t to_extract = parsing_buf.capacity() - parsing_buf.size();
1265:     do {
1266:       const size_t orig_size = parsing_buf.size();
1267:       parsing_buf.resize(parsing_buf.size() + to_extract);
1268: 
1269:       auto pb_size = parsing_buf.size();
1270:       auto pb_capacity = parsing_buf.capacity();
1271: 
1272:       const size_t received = io_base_t::recv_body(parsing_buf.data() + orig_size,
1273:                                                    to_extract);
1274: 
1275:       ldout(cct(), 20) << "AWSv4ComplMulti::recv_chunk() "
1276: 		     << "after io_base_t::recv_body recv pb_size: "
1277: 		     << pb_size
1278: 		     << " pb_capacity "
1279: 		     << pb_capacity
1280: 		     << " to_extract: "
1281: 		     << to_extract
1282: 		     << " received: "
1283: 		     << received
1284: 		     << dendl;
1285: 
1286:       parsing_buf.resize(parsing_buf.size() - (to_extract - received));
1287:       if (received == 0) {
1288:         eof = true;
1289:         break;
1290:       }
1291: 
1292:       stream_pos += received;
1293:       to_extract -= received;
1294:     } while (to_extract > 0);
1295: 
1296:     size_t consumed;
1297:     std::tie(chunk_meta, consumed) = \
1298:       ChunkMeta::create_next(cct(), std::move(chunk_meta),
1299: 	 parsing_buf.data(), parsing_buf.size(), flags);
1300: 
1301:     /* We can drop the bytes consumed during metadata parsing. The remainder
1302:      * can be chunk's data plus possibly beginning of next chunks' metadata. */
1303:     parsing_buf.erase(std::begin(parsing_buf),
1304:                       std::begin(parsing_buf) + consumed);
1305:   } /* if (chunk_meta.is_new_chunk_in_stream(stream_pos)) */
1306: 
1307:   size_t stream_pos_was = stream_pos - parsing_buf.size();
1308: 
1309:   size_t to_extract = \
1310:     std::min(chunk_meta.get_data_size(stream_pos_was), buf_max);
1311:   dout(30) << "AWSv4ComplMulti: stream_pos_was=" << stream_pos_was << ", to_extract=" << to_extract << dendl;
1312:   
1313:   /* It's quite probable we have a couple of real data bytes stored together
1314:    * with meta-data in the parsing_buf. We need to extract them and move to
1315:    * the final buffer. This is a trade-off between frontend's read overhead
1316:    * and memcpy. */
1317:   if (to_extract > 0 && parsing_buf.size() > 0) {
1318: 
1319:     const auto data_len = std::min(to_extract, parsing_buf.size());
1320:     const auto data_end_iter = std::begin(parsing_buf) + data_len;
1321: 
1322:     dout(30) << "AWSv4ComplMulti: to_extract=" << to_extract
1323: 	     << ", data_len=" << data_len
1324: 	     << dendl;
1325: 
1326:     /* if is-last-frag, then */
1327:     lf_bytes = stream_pos - stream_pos_was - data_len;
1328: 
1329:     std::copy(std::begin(parsing_buf), data_end_iter, buf);
1330:     parsing_buf.erase(std::begin(parsing_buf), data_end_iter);
1331: 
1332:     calc_hash_sha256_update_stream(sha256_hash, buf, data_len);
1333: 
1334:     to_extract -= data_len;
1335:     buf_pos += data_len;
1336:   }
1337: 
1338:   /* Now we can do the bulk read directly from RestfulClient without any extra
1339:    * buffering. */
1340:   while (to_extract > 0) {
1341:     const size_t received = io_base_t::recv_body(buf + buf_pos, to_extract);
1342:     dout(30) << "AWSv4ComplMulti: to_extract=" << to_extract << ", received=" << received << dendl;
1343: 
1344:     if (received == 0) {
1345:       eof = true;
1346:       break;
1347:     }
1348: 
1349:     calc_hash_sha256_update_stream(sha256_hash, buf + buf_pos, received);
1350: 
1351:     buf_pos += received;
1352:     stream_pos += received;
1353:     to_extract -= received;
1354:   }
1355: 
1356:   dout(20) << "AWSv4ComplMulti: filled=" << buf_pos << dendl;
1357:   return ReceiveChunkResult(buf_pos, chunk_meta.get_offset());
1358: } /* AWSv4Complmulti::recv_chunk */
