1390: /* the following templates capture the start (and for extract_helper)
1391:  * end boundaries of a substring match as constant strings, moving
1392:  * a small amount of work to compile time */
1393: 
1394: using ExtractResult = std::tuple<bool, std::string_view, size_t>;
1395: 
1396: /* adapted from here: https://ctrpeach.io/posts/cpp20-string-literal-template-parameters/ */
1397: template<size_t N>
1398: struct StringLiteral {
1399:     constexpr StringLiteral(const char (&str)[N]) {
1400:         std::copy_n(str, N, val);
1401:     }
1402:     char val[N];
1403: };
1404: 
1405: template <StringLiteral start, StringLiteral end>
1406: static inline ExtractResult mut_extract_helper(std::string_view& region) {
1407:   if (auto spos = region.find(start.val);
1408:       spos != std::string_view::npos) {
1409:     if (auto epos = region.find(end.val, spos + sarrlen(start.val));
1410: 	epos != std::string_view::npos) {
1411:       std::string_view matched = region.substr(spos, epos - spos);
1412:       auto consumed = matched.size() + sarrlen(end.val);
1413:       region.remove_prefix(consumed);
1414:       return ExtractResult(true, matched, spos + consumed);
1415:     }
1416:   }
1417:   return ExtractResult(false, "", 0);
1418: } /* mut_extract_helper <begin, end> */
1419: 
1420: template <StringLiteral end>
1421: static inline ExtractResult extract_helper(const std::string_view& region,
1422: 					   const std::string_view start) {
1423:   if (auto spos = region.find(start);
1424:       spos != std::string_view::npos) {
1425:     if (auto epos = region.find(end.val, spos + start.length());
1426: 	epos != std::string_view::npos) {
1427:       std::string_view matched = region.substr(spos, epos - spos);
1428:       auto consumed = matched.size() + sarrlen(end.val);
1429:       return ExtractResult(true, matched, consumed);
1430:     }
1431:   }
1432:   return ExtractResult(false, "", 0);
1433: } /* extract_helper <end> */
