1435: using split_func_t =
1436:   const fu2::unique_function<void(const std::string_view k,
1437: 				  const std::string_view v) const>;
1438: 
1439: static inline void split_header(const std::string_view hdr, split_func_t f)
1440: {
1441:   auto kv = ceph::split(hdr, ":");
1442:   auto k = kv.begin();
1443:   if (k != kv.end()) {
1444:     auto v = std::next(k);
1445:     if (v != kv.end()) [[likely]] {
1446:       f(*k, *v);
1447:     }
1448:   }
1449: } /* split_header */
