1451: inline void AWSv4ComplMulti::extract_trailing_headers(
1452:   std::string_view x_amz_trailer, std::string_view& mut_sv_trailer,
1453:   AWSv4ComplMulti::trailer_map_t& trailer_map)
1454: {
1455:   using std::get;
1456:   size_t consumed = 0;
1457:   /* spliterate x_amz_trailer */
1458:   auto kv = ceph::split(x_amz_trailer, ",");
1459:   for (auto k = kv.begin(); k != kv.end(); k = std::next(k)) {
1460:     /* extract trailer;  if there's more than one trailer, don't rely on their
1461:      * order in x-amz-trailer */
1462:     auto ex_header = extract_helper<"\r\n">(mut_sv_trailer, *k);
1463:     if (get<0>(ex_header)) {
1464:       auto header = get<1>(ex_header);
1465:       split_header(header, [&](const std::string_view k, const std::string_view v) -> void {
1466: 	if (cct()->_conf->subsys.should_gather(ceph_subsys_rgw, 10)) [[unlikely]] {
1467: 	  ldout(cct(), 10) << fmt::format("\nextracted trailing header {}={}", k, v) << dendl;
1468: 	}
1469: 	/* populate trailer map with expected headers and their values, if sent */
1470: 	trailer_map.insert(trailer_map_t::value_type(k, v));
1471: 	/* populate to req_info.env as well */
1472: 	put_prop(ys_header_mangle(k), v);
1473:       });
1474:       consumed += get<2>(ex_header);
1475:     } /* one trailer */
1476:   } /* foreach trailer */
1477:   /* advance mut_sv_trailer */
1478:   mut_sv_trailer.remove_prefix(consumed);
1479: } /* AWSv4complmulti::extract_trailing_headers */
