1481: size_t AWSv4ComplMulti::recv_body(char* const buf, const size_t buf_max)
1482: {
1483:   using std::get;
1484: 
1485:   bool eof = false;
1486:   size_t total = 0;
1487: 
1488:   ldout(cct(), 20) << "AWSv4ComplMulti::recv_body() buf_max: " << buf_max << dendl;
1489: 
1490:   uint32_t cnt = 0;
1491:   while (total < buf_max && !eof) {
1492:     ReceiveChunkResult rcr =
1493:       recv_chunk(buf + total, buf_max - total, cnt++, eof);
1494:     total += rcr.received;
1495:   }
1496: 
1497:   dout(20) << "AWSv4ComplMulti: received=" << total << dendl;
1498:   return total;
1499: }
