1524: bool AWSv4ComplMulti::complete()
1525: {
1526:   /* historically, this code has been validating not the final zero-length
1527:    * chunk, but the one before that; we'll do that as before, and then
1528:    * consume the last chunk signature and the trailer section */
1529:   if (is_signature_mismatched()) {
1530:     ldout(cct(), 10) << "ERROR: signature of last payload chunk does not match"
1531:                    << dendl;
1532:     return false;
1533:   } else {
1534:     /* now it's time to verify the signature of the last, zero-length chunk */
1535:     const auto string_to_sign = string_join_reserve("\n",
1536:     "AWS4-HMAC-SHA256-PAYLOAD",
1537:     date,
1538:     credential_scope,
1539:     prev_chunk_signature,
1540:     AWS4_EMPTY_PAYLOAD_HASH,
1541:     AWS4_EMPTY_PAYLOAD_HASH);
1542: 
1543:     const auto final_chunk_signature =
1544:       calc_hmac_sha256(signing_key, string_to_sign).to_str();
1545: 
1546:     ldout(cct(), 10) << "final chunk signature = "
1547: 		     << final_chunk_signature
1548: 		     << "\nprev_chunk_signature was "
1549: 		     << prev_chunk_signature
1550: 		     << dendl;
1551: 
1552:     /* in the last-chunk case, parsing_buf potentially holds unconsumed
1553:      * data, including the final chunk boundary */
1554:     std::string_view last_frag(parsing_buf.begin().get_ptr(), lf_bytes);
1555: 
1556:     size_t tbuf_pos = 0;
1557: 
1558:     static constexpr size_t trailer_buf_size = 256;
1559:     boost::container::static_vector<char, trailer_buf_size> trailer_vec;
1560: 
1561:     std::copy(parsing_buf.begin(), parsing_buf.begin() + lf_bytes,
1562:               trailer_vec.begin());
1563:     tbuf_pos += lf_bytes;
1564: 
1565:     while (tbuf_pos < trailer_buf_size) {
1566:       const size_t received =
1567:           io_base_t::recv_body(trailer_vec.data() + tbuf_pos,
1568: 			       trailer_buf_size - tbuf_pos - 1);
1569:       dout(30) << "AWSv4ComplMulti: recv trailer received=" << received
1570:                << dendl;
1571:       if (received == 0) {
1572:         break;
1573:       }
1574:       tbuf_pos += received;
1575:     }
1576: 
1577:     if (tbuf_pos == trailer_buf_size) {
1578:       ldout(cct(), 10) << "AWSv4ComplMulti:: recv trailer exceeded size limit of "
1579: 		       << trailer_buf_size - 1
1580: 		       << " bytes"
1581: 		       << dendl;
1582:       throw rgw::io::Exception(ERR_LIMIT_EXCEEDED, std::system_category());
1583:     }
1584: 
1585:     std::string_view expected_trailer_signature;
1586:     std::string calculated_trailer_signature;
1587: 
1588:     /* I have seen variations in the 0-byte case, with and without
1589:      * ssl transport. I have observed "\r\n0;" but also "0;" in the
1590:      * trailer-signature case.  I have observed only "\r\n0" in the
1591:      * no-trailer-signature case--but assume "0" might be possible.
1592:      * The logic below handles all 4 cases. */
1593:     if (tbuf_pos > sarrlen("\r\n0")) {
1594:       const char* tv_data = trailer_vec.data();
1595:       auto trailer_off = 0;
1596:       if (*(tv_data + trailer_off) == '\r') {
1597: 	trailer_off += 2;
1598:       }
1599:       if (*(tv_data + trailer_off) == '0') {
1600: 	++trailer_off;
1601:       }
1602:       if (*(tv_data + trailer_off) == ';') {
1603: 	++trailer_off;
1604:       }
1605:       const std::string_view sv_trailer(
1606:         trailer_vec.data() + trailer_off, tbuf_pos - trailer_off);
1607: 
1608:       if (cct()->_conf->subsys.should_gather(ceph_subsys_rgw, 10)) [[unlikely]] {
1609:         ldout(cct(), 10) << "trailer_section: " << sv_trailer << dendl;
1610:       }
1611: 
1612:       std::string_view mut_sv_trailer(sv_trailer);
1613: 
1614:       auto chunk_signature =
1615:           mut_extract_helper<"chunk-signature=", "\r\n">(mut_sv_trailer);
1616: 
1617:       std::string_view sig_sv;
1618:       if (get<0>(chunk_signature)) {
1619:         sig_sv = get<1>(chunk_signature);
1620:         sig_sv.remove_prefix(sarrlen("chunk-signature="));
1621: 
1622:         ldout(cct(), 10) << "expected last chunk signature: " << sig_sv
1623:                          << " remaining: " << mut_sv_trailer << dendl;
1624:       }
1625: 
1626:       trailer_map_t trailer_map;
1627: 
1628:       if (x_amz_trailer) {
1629:         extract_trailing_headers(*x_amz_trailer, mut_sv_trailer, trailer_map);
1630:       }
1631: 
1632:       auto trailer_signature =
1633:           mut_extract_helper<"x-amz-trailer-signature:", "\r\n">(
1634:               mut_sv_trailer);
1635:       if (get<0>(trailer_signature)) {
1636:         auto trailing_sig = get<1>(trailer_signature);
1637:         split_header(
1638:             trailing_sig,
1639:             [&](const std::string_view k, const std::string_view v) -> void {
1640:               expected_trailer_signature = v;
1641:             });
1642: 
1643:         calculated_trailer_signature =
1644:             calc_v4_trailer_signature(trailer_map, final_chunk_signature);
1645: 
1646:         ldout(cct(), 10) << "expected trailer signature="
1647:                          << expected_trailer_signature
1648:                          << "\n calculated trailer signature="
1649:                          << calculated_trailer_signature
1650:                          << "\n trailer bytes remaining/not consumed: "
1651:                          << mut_sv_trailer << dendl;
1652:       } /* matched trailer signature */
1653:     } /* have trailer */
1654: 
1655:     if (expect_trailer_signature() &&
1656: 	(expected_trailer_signature.empty() ||
1657: 	 (calculated_trailer_signature != expected_trailer_signature))) {
1658:       throw rgw::io::Exception(ERR_SIGNATURE_NO_MATCH, std::system_category());
1659:     }
1660: 
1661:     return true;
1662:   }
1663: } /* AWSv4Complmulti:: complete */
